class Solution {
    public int coinChange(int[] coins, int amount) {
        return coinChangeHelper(coins, amount, 0);
    }

    private int coinChangeHelper(int[] coins, int amount, int count) {
        if (amount == 0) {
            return count;
        }
        if (amount < 0) {
            return Integer.MAX_VALUE;
        }

        int minCoins = Integer.MAX_VALUE;
        for (int coin : coins) {
            int result = coinChangeHelper(coins, amount - coin, count + 1);
            minCoins = Math.min(minCoins, result);
        }

        return minCoins;
    }
}

