from typing import List

def coinChange(coins: List[int], amount: int) -> int:
    def backtrack(remaining, count):
        if remaining == 0:
            return count
        if remaining < 0:
            return float('inf')
        min_count = float('inf')
        for coin in coins:
            min_count = min(min_count, backtrack(remaining - coin, count + 1))
        return min_count

    result = backtrack(amount, 0)
    return result if result != float('inf') else -1

